class CounterThread implements Runnable {
    private String name;

    CounterThread(String name) {
        this.name = name;
    }

    @Override
    public void run() {
        for (int i = 1; i <= 5; i++) {
            System.out.println(name + ": " + i);
            try {
                Thread.sleep(100);
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }
    }
}

public class Main {
    public static void main(String[] args) throws InterruptedException {
        Thread t1 = new Thread(new CounterThread("Thread A"));
        Thread t2 = new Thread(new CounterThread("Thread B"));
        Thread t3 = new Thread(new CounterThread("Thread C"));

        t1.start();
        t2.start();
        t3.start();

        // Wait for threads to finish
        t1.join();
        t2.join();
        t3.join();

        System.out.println("All threads finished");
    }
}
